/**
 * Validates a skill name against the Agent Skills RFC specification.
 *
 * Rules:
 * - 1-64 characters
 * - Lowercase alphanumeric and hyphens only (a-z, 0-9, -)
 * - Must not start or end with a hyphen
 * - Must not contain consecutive hyphens
 */
export declare function isValidSkillName(name: string): boolean;
/**
 * Returns validation error message for an invalid skill name, or null if valid.
 */
export declare function getSkillNameValidationError(name: string): string | null;
/**
 * Gets the MIME type for a file based on its extension.
 */
export declare function getMimeType(filePath: string): string;
/**
 * Determines if a file should be treated as binary (and base64-encoded).
 */
export declare function isBinaryFile(filePath: string): boolean;
/**
 * Converts a file path to use forward slashes (for consistent storage keys)
 */
export declare function normalizeFilePath(filePath: string): string;
